from __future__ import annotations

import base64
import re
from pathlib import Path

GENERATOR = Path("src/hadocs/reports/generator.py")
HOOK = Path("src/hadocs/reports/html_hook.py")

PRO_DASHBOARD_FUNCTION = base64.b64decode("").decode("utf-8")


def replace_function(source: str, name: str, replacement: str) -> str:
    match = re.search(rf"^def {re.escape(name)}\([^)]*\):\n", source, flags=re.MULTILINE)
    if not match:
        raise RuntimeError(f"Could not find function {name}")

    start = match.start()
    next_def = re.search(r"^def [A-Za-z_][A-Za-z0-9_]*\(", source[match.end():], flags=re.MULTILINE)
    end = match.end() + next_def.start() if next_def else len(source)
    return source[:start] + replacement.rstrip() + "\n\n" + source[end:].lstrip("\n")


def remove_html_hook_usage(source: str) -> str:
    source = source.replace("from src.hadocs.reports.html_hook import generate_html_dashboard\n", "")
    lines = source.splitlines(True)
    out = []
    i = 0
    while i < len(lines):
        if lines[i].startswith("    generate_html_dashboard("):
            depth = lines[i].count("(") - lines[i].count(")")
            i += 1
            while i < len(lines) and depth > 0:
                depth += lines[i].count("(") - lines[i].count(")")
                i += 1
            continue
        out.append(lines[i])
        i += 1
    return "".join(out)


def ensure_dashboard_call(source: str) -> str:
    call = "generate_executive_dashboard(out, project_name, model, executive, health_notes, history_comparison, trend_summary, incidents, raw_incidents, now)"
    if call in source:
        return source

    needle = "generate_index(out, project_name, executive, incidents, now)\n"
    if needle not in source:
        raise RuntimeError("Could not find generate_index call inside generate_all")
    return source.replace(needle, needle + call + "\n", 1)


def main():
    if not GENERATOR.exists():
        raise SystemExit("Run from repository root")

    source = GENERATOR.read_text(encoding="utf-8")
    source = remove_html_hook_usage(source)
    source = replace_function(source, "generate_executive_dashboard", PRO_DASHBOARD_FUNCTION)
    source = ensure_dashboard_call(source)
    GENERATOR.write_text(source, encoding="utf-8")

    if HOOK.exists():
        hook_text = """\"\"\"Backward-compatible external wrapper.

Internal report generation no longer uses this module.
\"\"\"


def generate_html_dashboard(*args, **kwargs):
    from src.hadocs.reports.generator import generate_executive_dashboard
    return generate_executive_dashboard(*args, **kwargs)
"""
        HOOK.write_text(hook_text, encoding="utf-8")

    print("Report engine cleanup applied.")
    print("- generator.py no longer calls html_hook internally")
    print("- generate_executive_dashboard now writes professional output/index.html")
    print("")
    print("Run:")
    print("  py -3.14 -m pytest")
    print("  py -3.14 main.py")
    print("")
    print("After scan:")
    print("  dir output\\index.html")
    print("")
    print("Commit:")
    print("  git add src/hadocs/reports/generator.py src/hadocs/reports/html_hook.py docs/V101_REPORT_ENGINE_CLEANUP.md tools/report_engine_cleanup.py")
    print('  git commit -m "Clean up report engine and restore dashboard"')
    print("  git push")


if __name__ == "__main__":
    main()
